  ('Sunset Boulevard',                              'Sunset Boulevard',                              1950, 'Drama',     'Billy Wilder',                         110, 'English',    'USA',         'G',     8.4, 'Un scénariste fauché se retrouve piégé dans la demeure d''une star déchue du cinéma muet.'),
  ('Double Indemnity',                              'Double Indemnity',                              1944, 'Crime',     'Billy Wilder',                         107, 'English',    'USA',         'G',     8.3, 'Un agent d''assurance tombe sous le charme d''une femme manipulatrice et devient complice d''un crime.')
) AS v(title, original_title, release_year, genre, director, duration_minutes, language, country, age_rating, imdb_score, synopsis)
